  ],
  "questionProse": [
    "इनपुट साइज़ की परवाह किए बिना, हमेशा समान समय लेने वाले एल्गोरिदम की टाइम कॉम्प्लेक्सिटी क्या होती है?"
  ],
  "explanationProse": [
    "O(1) कॉन्स्टेंट टाइम कॉम्प्लेक्सिटी (constant time complexity) को दर्शाता है। इसका सीधा मतलब है कि इनपुट कितना भी बड़ा या छोटा हो, एल्गोरिदम को रन होने में हमेशा उतना ही समय लगेगा।"
  ]
}
